import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        String[] words = {"apple", "banana", "apple", "cherry", "apple", "banana"};

        Map<String, Integer> counts = new HashMap<>();
        for (String word : words) {
            counts.put(word, counts.getOrDefault(word, 0) + 1);
        }

        System.out.println("apple appears " + counts.get("apple") + " times");
        System.out.println("banana appears " + counts.get("banana") + " times");
        System.out.println("cherry appears " + counts.get("cherry") + " times");
    }
}

