import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        String[] votes = {"pizza", "tacos", "pizza", "pizza", "tacos"};

        Map<String, Integer> tally = new HashMap<>();
        Set<String> foods = new HashSet<>();
        for (String vote : votes) {
            tally.put(vote, tally.getOrDefault(vote, 0) + 1);
            foods.add(vote);
        }

        System.out.println("Different foods: " + foods.size());
        System.out.println("pizza votes: " + tally.get("pizza"));
        System.out.println("tacos votes: " + tally.get("tacos"));
    }
}
